/// Returns the default path to the smedja ingot database.
///
/// The database lives under the XDG data directory so that it is isolated
/// from per-workspace `.smedja/` directories.
fn default_ingot_path() -> PathBuf {
    let data_home = std::env::var("XDG_DATA_HOME").map_or_else(
        |_| {
            std::env::var("HOME").map_or_else(
                |_| PathBuf::from(".local/share"),
                |h| PathBuf::from(h).join(".local/share"),
            )
        },
        PathBuf::from,
    );
    let dir = data_home.join("smedja");
    // Best-effort directory creation — open() will surface the error if it fails.
    let _ = std::fs::create_dir_all(&dir);
    dir.join("ingot.db")
}

fn default_socket_path() -> PathBuf {
    let base = std::env::var("XDG_RUNTIME_DIR").unwrap_or_else(|_| "/tmp".into());
    PathBuf::from(base).join("smdjad.sock")
}

/// Resolves the XDG config base directory.
///
/// Priority order:
/// 1. `$XDG_CONFIG_HOME` — if set and non-empty
/// 2. `$HOME/.config` — if `$HOME` is set
/// 3. `.config` — relative fallback (should not occur in practice)
fn xdg_config_dir() -> PathBuf {
    std::env::var("XDG_CONFIG_HOME").map_or_else(
        |_| {
            std::env::var("HOME").map_or_else(
                |_| PathBuf::from(".config"),
                |h| PathBuf::from(h).join(".config"),
            )
        },
        PathBuf::from,
    )
}

#[allow(clippy::too_many_lines)] // all CLI command arms live in one function per the spec
#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt::init();
    let cli = Cli::parse();
    let sock = cli.sock.unwrap_or_else(default_socket_path);

    match cli.command {
        Cmd::Daemon { action } => match action {
            DaemonCmd::Status => cmd_daemon_status(&sock).await?,
            DaemonCmd::Start => cmd_daemon_start()?,
            DaemonCmd::Stop => {
                let base = std::env::var("XDG_RUNTIME_DIR").unwrap_or_else(|_| "/tmp".into());
                let pid_path = std::path::PathBuf::from(base).join("smdjad.pid");
                let pid = std::fs::read_to_string(&pid_path)
                    .context("smdjad not running (no PID file)")?
                    .trim()
                    .to_owned();
                std::process::Command::new("kill")
                    .args(["-TERM", &pid])
                    .status()
                    .context("kill -TERM failed")?;
                println!("smdjad stopped (pid {pid})");
            }
            DaemonCmd::Restart => {
                let base = std::env::var("XDG_RUNTIME_DIR").unwrap_or_else(|_| "/tmp".into());
                let pid_path = std::path::PathBuf::from(base).join("smdjad.pid");
                if let Ok(pid) = std::fs::read_to_string(&pid_path).map(|s| s.trim().to_owned()) {
                    let _ = std::process::Command::new("kill")
                        .args(["-TERM", &pid])
                        .status();
                    std::thread::sleep(std::time::Duration::from_millis(500));
                }
                cmd_daemon_start()?;
                println!("smdjad restarted");
            }
        },
        Cmd::Skill { action } => {
            let registry = SkillRegistry::new(SkillRegistry::default_path());
            match action {
                SkillCmd::List => cmd_skill_list(&registry)?,
                SkillCmd::Install { path } => cmd_skill_install(&registry, &path)?,
                SkillCmd::Update { name, path } => cmd_skill_update(&registry, &name, &path)?,
                SkillCmd::Remove { name } => cmd_skill_remove(&registry, &name)?,
                SkillCmd::Sync { path } => cmd_skill_sync(&registry, &path)?,
            }
        }
        Cmd::Task { action } => {
            // Export and Import operate on the local Ingot DB directly without
            // needing a running smdjad daemon.
            match action {
                TaskCmd::Export { change } => {
                    let db_path = default_ingot_path();
                    let ingot = Ingot::open(&db_path).with_context(|| {
                        format!("failed to open ingot at {}", db_path.display())
                    })?;
                    let records = ingot
                        .export_jsonl(change.as_deref())
                        .context("export_jsonl failed")?;
                    for rec in &records {
                        println!("{}", serde_json::to_string(rec)?);
                    }
                    return Ok(());
                }
                TaskCmd::Import => {
                    use std::io::BufRead as _;
                    let db_path = default_ingot_path();
                    let mut ingot = Ingot::open(&db_path).with_context(|| {
                        format!("failed to open ingot at {}", db_path.display())
                    })?;
                    let stdin = std::io::stdin();
                    let mut records: Vec<serde_json::Value> = Vec::new();
                    for line in stdin.lock().lines() {
                        let line = line.context("failed to read stdin")?;
                        let line = line.trim().to_owned();
                        if line.is_empty() {
                            continue;
                        }
                        let val: serde_json::Value =
                            serde_json::from_str(&line).context("invalid JSON line")?;
                        records.push(val);
                    }
                    let n = ingot
                        .import_jsonl(&records)
                        .context("import_jsonl failed")?;
                    println!("Imported {n} record(s)");
                    return Ok(());
                }
                _ => {}
            }

            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            match action {
                TaskCmd::List { status } => cmd_task_list(&mut client, status.as_deref()).await?,
                TaskCmd::Show { id } => cmd_task_show(&mut client, &id).await?,
                TaskCmd::Create { title, description } => {
                    cmd_task_create(&mut client, &title, description.as_deref()).await?;
                }
                TaskCmd::Close { id } => cmd_task_close(&mut client, &id).await?,
                TaskCmd::Parallel { goal, roles } => {
                    let resp = client
                        .call("task.parallel", json!({ "goal": goal, "roles": roles }))
                        .await
                        .context("task.parallel failed")?;
                    if let Some(tasks) = resp["tasks"].as_array() {
                        for t in tasks {
                            println!(
                                "{} ({})",
                                t["task_id"].as_str().unwrap_or("?"),
                                t["role"].as_str().unwrap_or("?"),
                            );
                        }
                    }
                }
                TaskCmd::Status { id } => {
                    let resp = client
                        .call("task.get", json!({ "id": id }))
                        .await
                        .context("task.get failed")?;
                    println!(
                        "{}",
                        serde_json::to_string_pretty(&resp).unwrap_or_default()
                    );
                }
                TaskCmd::Cancel { id } => {
                    client
                        .call("task.cancel", json!({ "task_id": id }))
                        .await
                        .context("task.cancel failed")?;
                    println!("cancelled: {id}");
                }
                // Already handled above; unreachable but required for exhaustiveness.
                TaskCmd::Export { .. } | TaskCmd::Import => unreachable!(),
            }
        }
        Cmd::Session { action } => {
            if let SessionCmd::Blocks { id } = action {
                // ponytail: blocks are in-memory in the TUI; smj can only call the
                // smdjad RPC if one is wired, so for now print a message.
                println!(
                    "smj session blocks {id}: requires smdjad 'session.blocks' RPC (not yet wired)"
                );
            } else {
                let mut client = Client::connect(&sock)
                    .await
                    .with_context(|| format!("smdjad not running ({})", sock.display()))?;
                match action {
                    SessionCmd::Start { cowork, task } => {
                        let resp = client
                            .call(
                                "session.create",
                                json!({
                                    "cowork_mode": cowork,
                                    "task_description": task,
                                }),
                            )
                            .await
                            .context("session.create failed")?;
                        let session_id = resp["id"].as_str().unwrap_or("?");
                        println!("Session: {session_id}");
                        if let Some(task_id) = resp["task_id"].as_str() {
                            println!("Task created: {task_id}");
                        }
                    }
                    SessionCmd::List => cmd_session_list(&mut client).await?,
                    SessionCmd::Show { id } => cmd_session_show(&mut client, &id).await?,
                    SessionCmd::Rollback { id, turn } => {
                        cmd_session_rollback(&mut client, &id, turn).await?;
                    }
                    SessionCmd::Fork { id, .. } => {
                        let resp = client
                            .call("session.fork", json!({ "session_id": id }))
                            .await
                            .context("session.fork failed")?;
                        println!(
                            "Forked: {} → {}",
                            id,
                            resp["session_id"].as_str().unwrap_or("?")
                        );
                    }
                    SessionCmd::Checkpoint { id } => {
                        let resp = client
                            .call("session.checkpoint.list", json!({ "session_id": id }))
                            .await
                            .context("session.checkpoint.list failed")?;
                        if let Some(arr) = resp.as_array() {
                            for cp in arr {
                                println!(
                                    "turn={} ts={} messages={}",
                                    cp["turn_n"].as_i64().unwrap_or(-1),
                                    cp["created_at"].as_f64().unwrap_or(0.0),
                                    cp["message_count"].as_u64().unwrap_or(0),
                                );
                            }
                        }
                    }
                    SessionCmd::Blocks { .. } => unreachable!(),
                    SessionCmd::Export { id } => {
                        let resp = client
                            .call("session.export", json!({ "id": id }))
                            .await
                            .context("session.export failed")?;
                        println!("{}", serde_json::to_string_pretty(&resp)?);
                    }
                    SessionCmd::Compact { id } => {
                        let resp = client
                            .call("session.compact", json!({ "session_id": id }))
                            .await
                            .context("session.compact failed")?;
                        let summary = resp["summary"].as_str().unwrap_or("(no summary)");
                        println!("Compaction summary for {id}:\n{summary}");
                    }
                    SessionCmd::Tokens { id } => {
                        let resp = client
                            .call("session.token_usage", json!({ "session_id": id }))
                            .await
                            .context("session.token_usage failed")?;
                        if let Some(arr) = resp.as_array() {
                            println!(
                                "{:<8} {:<12} {:<12} {:<16} {:<16}",
                                "turn_n", "input_tok", "output_tok", "cum_input", "cum_output"
                            );
                            println!("{}", "-".repeat(68));
                            for snap in arr {
                                println!(
                                    "{:<8} {:<12} {:<12} {:<16} {:<16}",
                                    snap["turn_n"].as_i64().unwrap_or(-1),
                                    snap["input_tok"].as_i64().unwrap_or(0),
                                    snap["output_tok"].as_i64().unwrap_or(0),
                                    snap["cumulative_input"].as_i64().unwrap_or(0),
                                    snap["cumulative_output"].as_i64().unwrap_or(0),
                                );
                            }
                        }
                    }
                }
            }
        }
        Cmd::Cost { session, .. } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            let session_id = session.unwrap_or_default();
            if session_id.is_empty() {
                println!("smj cost: --session <session-id> required");
                return Ok(());
            }
            let resp = client
                .call("session.cost", json!({"session_id": session_id}))
                .await
                .context("session.cost failed")?;
            let usd = resp["total_usd"].as_f64().unwrap_or(0.0);
            println!("SESSION  {session_id}  TOTAL  ${usd:.6}");
            if let Some(rows) = resp["breakdown"].as_array() {
                if !rows.is_empty() {
                    println!();
                    println!(
                        "{:<32}  {:<12}  {:>5}  {:>8}  {:>8}  {:>10}",
                        "MODEL", "RUNNER", "TURNS", "INPUT", "OUTPUT", "COST"
                    );
                    println!("{}", "-".repeat(82));
                    for row in rows {
                        let model = row["model"].as_str().unwrap_or("-");
                        let runner = row["runner"].as_str().unwrap_or("-");
                        let turns = row["turns"].as_i64().unwrap_or(0);
                        let input = row["input_tok"].as_i64().unwrap_or(0);
                        let output = row["output_tok"].as_i64().unwrap_or(0);
                        let cost = row["cost_usd"].as_f64().unwrap_or(0.0);
                        println!(
                            "{model:<32}  {runner:<12}  {turns:>5}  {input:>8}  {output:>8}  ${cost:.6}",
                        );
                    }
                }
            }
        }
        Cmd::Workspace { action } => match action {
            WorkspaceCmd::Agents {
                action: agents_action,
            } => match agents_action {
                AgentsCmd::Show => cmd_workspace_agents()?,
                AgentsCmd::Init => {
                    let target = std::path::Path::new(".smedja");
                    std::fs::create_dir_all(target)?;
                    let agents_toml = target.join("agents.toml");
                    if agents_toml.exists() {
                        anyhow::bail!(".smedja/agents.toml already exists");
                    }
                    std::fs::write(&agents_toml, AGENTS_TOML_TEMPLATE)?;
                    println!("Created {}", agents_toml.display());
                }
            },
            WorkspaceCmd::Init { path } => {
                let target = path.unwrap_or_else(|| std::env::current_dir().expect("cwd"));
                if !target.exists() {
                    anyhow::bail!("path does not exist: {}", target.display());
                }
                cmd_workspace_init(&target)?;
            }
            WorkspaceCmd::Index { commit_sha } => {
                let workspace =
                    std::env::current_dir().context("cannot determine current directory")?;
                let db_path = workspace.join(".smedja").join("graph.db");
                std::fs::create_dir_all(workspace.join(".smedja"))?;
                let mut store = smedja_graph::GraphStore::open(&db_path)
                    .context("failed to open graph store")?;
                let count = store
                    .index_workspace_incremental(&workspace, "workspace", commit_sha.as_deref())
                    .context("indexing failed")?;
                println!("Indexed {count} symbols in {}", workspace.display());
            }
            WorkspaceCmd::Add { path } => {
                let workspace =
                    std::env::current_dir().context("cannot determine current directory")?;
                let smedja_dir = workspace.join(".smedja");
                std::fs::create_dir_all(&smedja_dir)?;
                let toml_path = smedja_dir.join("workspace.toml");

                // Read existing content or start fresh.
                let mut content = if toml_path.exists() {
                    std::fs::read_to_string(&toml_path).context("failed to read workspace.toml")?
                } else {
                    String::new()
                };

                // Append the new path entry.
                if !content.is_empty() && !content.ends_with('\n') {
                    content.push('\n');
                }
                content.push_str("\n[[workspace.paths]]\npath = \"");
                content.push_str(&path);
                content.push_str("\"\n");
                std::fs::write(&toml_path, &content).context("failed to write workspace.toml")?;
                println!("Added path '{}' to {}", path, toml_path.display());
            }
        },
        Cmd::Audit { action } => match action {
            AuditCmd::Query {
                session,
                since,
                action,
            } => {
                let mut client = Client::connect(&sock)
                    .await
                    .with_context(|| format!("smdjad not running ({})", sock.display()))?;
                let mut params = serde_json::json!({});
                if let Some(sid) = session {
                    params["session_id"] = serde_json::Value::String(sid);
                }
                if let Some(s) = since {
                    params["since"] = serde_json::Value::String(s);
                }
                if let Some(a) = action {
                    params["action_type"] = serde_json::Value::String(a);
                }
                let resp = client
                    .call("audit.list", params)
                    .await
                    .context("audit.list failed")?;
                println!("{}", serde_json::to_string_pretty(&resp)?);
            }
            AuditCmd::PromptDiff { change } => {
                let db_path = default_ingot_path();
                let ingot = Ingot::open(&db_path)
                    .with_context(|| format!("failed to open ingot at {}", db_path.display()))?;
                let hashes = ingot
                    .list_prompt_hashes(&change)
                    .context("list_prompt_hashes failed")?;
                if hashes.is_empty() {
                    println!("No prompt hashes recorded for change '{change}'");
                } else {
                    println!("{:<20} {:<64} ts", "role", "hash");
                    println!("{}", "-".repeat(90));
                    for h in &hashes {
                        println!("{:<20} {:<64} {}", h.role, h.hash, h.ts);
                    }
                }
            }
            AuditCmd::Who { session } => {
                let mut client = Client::connect(&sock)
                    .await
                    .with_context(|| format!("smdjad not running ({})", sock.display()))?;
                let resp = client
                    .call("audit.list", json!({ "session_id": session }))
                    .await
                    .context("audit.list failed")?;
                // Group by role_id → action_type → count.
                let mut counts: std::collections::HashMap<
                    String,
                    std::collections::HashMap<String, u64>,
                > = std::collections::HashMap::new();
                if let Some(events) = resp["events"].as_array() {
                    for ev in events {
                        let role_id = ev["role_id"].as_str().unwrap_or("(no role)").to_owned();
                        let action = ev["action_type"].as_str().unwrap_or("?").to_owned();
                        *counts
                            .entry(role_id)
                            .or_default()
                            .entry(action)
                            .or_insert(0) += 1;
                    }
                }
                println!("{:<36} {:<20} count", "role_id", "action_type");
                println!("{}", "-".repeat(64));
                let mut rows: Vec<(String, String, u64)> = counts
                    .into_iter()
                    .flat_map(|(role, actions)| {
                        actions
                            .into_iter()
                            .map(move |(action, count)| (role.clone(), action, count))
                    })
                    .collect();
                rows.sort_by(|a, b| a.0.cmp(&b.0).then(a.1.cmp(&b.1)));
                for (role_id, action, count) in &rows {
                    println!("{role_id:<36} {action:<20} {count}");
                }
            }
            AuditCmd::Export {
                change,
                format,
                include_prompts,
            } => {
                let db_path = default_ingot_path();
                let ingot = Ingot::open(&db_path)
                    .with_context(|| format!("failed to open ingot at {}", db_path.display()))?;
                let events = ingot
                    .list_all_audit_events()
                    .context("list_all_audit_events failed")?;
                // Build optional prompt hash lookup: role → hash.
                let prompt_hashes: std::collections::HashMap<String, String> = if include_prompts {
                    ingot
                        .list_prompt_hashes(&change)
                        .unwrap_or_default()
                        .into_iter()
                        .map(|r| (r.role, r.hash))
                        .collect()
                } else {
                    std::collections::HashMap::new()
                };

                match format.as_str() {
                    "csv" => {
                        if include_prompts {
                            println!(
                                "role_id,session_id,tool_name,args_hash,result_tokens,traceparent,ts,prompt_hash"
                            );
                        } else {
                            println!(
                                "role_id,session_id,tool_name,args_hash,result_tokens,traceparent,ts"
                            );
                        }
                        for ev in &events {
                            let role_id = ev.role_id.as_deref().unwrap_or("");
                            let tool = ev.tool_name.as_deref().unwrap_or("");
                            let tp = ev.traceparent.as_deref().unwrap_or("");
                            if include_prompts {
                                let ph = prompt_hashes.get(role_id).map_or("", String::as_str);
                                println!(
                                    "{role_id},{},{tool},,{},{tp},{},{}",
                                    ev.session_id, ev.output_tok, ev.ts, ph
                                );
                            } else {
                                println!(
                                    "{role_id},{},{tool},,{},{tp},{}",
                                    ev.session_id, ev.output_tok, ev.ts
                                );
                            }
                        }
                    }
                    _ => {
                        // Default: jsonl
                        for ev in &events {
                            let role_id = ev.role_id.as_deref().unwrap_or("");
                            let mut obj = serde_json::json!({
                                "role_id": role_id,
                                "session_id": ev.session_id,
                                "tool_name": ev.tool_name,
                                "args_hash": "",
                                "result_tokens": ev.output_tok,
                                "traceparent": ev.traceparent,
                                "ts": ev.ts,
                            });
                            if include_prompts {
                                let ph = prompt_hashes.get(role_id).map_or("", String::as_str);
                                obj["prompt_hash"] = serde_json::Value::String(ph.to_owned());
                            }
                            println!("{}", serde_json::to_string(&obj)?);
                        }
                    }
                }
            }
        },
        Cmd::Loop { action } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            match action {
                LoopCmd::Run { change, max_slices } => {
                    let resp = client
                        .call(
                            "loop.create",
                            json!({ "change_name": change, "max_slices": max_slices }),
                        )
                        .await
                        .context("loop.create failed")?;
                    let loop_id = resp["loop_id"]
                        .as_str()
                        .ok_or_else(|| anyhow::anyhow!("loop.create returned no loop_id"))?
                        .to_owned();
                    client
                        .call("loop.run", json!({ "loop_id": loop_id }))
                        .await
                        .context("loop.run failed")?;
                    println!("Loop {loop_id} running");
                }
                LoopCmd::Status { change } => {
                    let resp = client
                        .call("loop.list", json!({ "change_name": change }))
                        .await
                        .context("loop.list failed")?;
                    println!(
                        "{}",
                        serde_json::to_string_pretty(&resp).unwrap_or_default()
                    );
                }
                LoopCmd::Cancel { change } => {
                    let resp = client
                        .call("loop.list", json!({ "change_name": change }))
                        .await
                        .context("loop.list failed")?;
                    let active = resp["loops"]
                        .as_array()
                        .and_then(|arr| {
                            arr.iter().find(|r| {
                                let status = r["status"].as_str().unwrap_or("");
                                status != "cancelled" && status != "done"
                            })
                        })
                        .and_then(|r| r["id"].as_str())
                        .map(str::to_owned);
                    match active {
                        Some(loop_id) => {
                            client
                                .call("loop.cancel", json!({ "loop_id": loop_id }))
                                .await
                                .context("loop.cancel failed")?;
                            println!("Loop {loop_id} cancelled");
                        }
                        None => {
                            println!("No active loop for change {change}");
                        }
                    }
                }
                LoopCmd::Retire { change } => {
                    // Find the most recent complete or failed loop for this change.
                    let resp = client
                        .call("loop.list", json!({ "change_name": change }))
                        .await
                        .context("loop.list failed")?;
                    let loop_id = resp["loops"]
                        .as_array()
                        .and_then(|arr| {
                            arr.iter().find(|r| {
                                let status = r["status"].as_str().unwrap_or("");
                                status == "complete" || status == "failed"
                            })
                        })
                        .and_then(|r| r["id"].as_str())
                        .map(str::to_owned)
                        .ok_or_else(|| {
                            anyhow::anyhow!(
                                "No complete or failed loop found for change '{change}'"
                            )
                        })?;
                    client
                        .call("loop.retire", json!({ "loop_id": loop_id }))
                        .await
                        .context("loop.retire failed")?;
                    // Export audit events for the change to a JSONL file.
                    let db_path = default_ingot_path();
                    let out_path = format!("{change}.loop-audit.jsonl");
                    if let Ok(ingot) = Ingot::open(&db_path) {
                        if let Ok(events) = ingot.list_all_audit_events() {
                            if let Ok(mut f) = std::fs::File::create(&out_path) {
                                use std::io::Write as _;
                                for ev in &events {
                                    if let Ok(line) = serde_json::to_string(ev) {
                                        let _ = writeln!(f, "{line}");
                                    }
                                }
                            }
                        }
                    }
                    println!("Loop {loop_id} retired");
                    println!("Audit export: {out_path}");
                }
                LoopCmd::List { status } => {
                    let mut params = serde_json::json!({});
                    if let Some(s) = status {
                        params["status"] = serde_json::Value::String(s);
                    }
                    let resp = client
                        .call("loop.list_by_status", params)
                        .await
                        .context("loop.list_by_status failed")?;
                    if let Some(loops) = resp["loops"].as_array() {
                        println!(
                            "{:<36} {:<20} {:<12} {:<16} updated_at",
                            "id", "change_name", "status", "created_at"
                        );
                        println!("{}", "-".repeat(100));
                        for rec in loops {
                            println!(
                                "{:<36} {:<20} {:<12} {:<16} {}",
                                rec["id"].as_str().unwrap_or("?"),
                                rec["change_name"].as_str().unwrap_or("?"),
                                rec["status"].as_str().unwrap_or("?"),
                                rec["created_at"].as_f64().unwrap_or(0.0),
                                rec["updated_at"].as_f64().unwrap_or(0.0),
                            );
                        }
                    }
                }
            }
        }
        Cmd::Sandbox { action } => match action {
            SandboxCmd::Build => {
                println!("Building smedja-sandbox:latest...");
                let status = std::process::Command::new("docker")
                    .args(["build", "-t", "smedja-sandbox:latest", "scripts/sandbox/"])
                    .status()
                    .map_err(|e| anyhow::anyhow!("docker not found: {e}"))?;
                if status.success() {
                    println!("Image built successfully.");
                } else {
                    anyhow::bail!("docker build failed");
                }
            }
        },
        Cmd::Mcp { action } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            match action {
                McpCmd::Add { name, url, stdio } => {
                    let resp = client
                        .call(
                            "mcp.register",
                            json!({
                                "name": name,
                                "url": url,
                                "transport": if stdio.is_some() { "stdio" } else { "http" },
                                "tools_json": null,
                            }),
                        )
                        .await
                        .context("mcp.register failed")?;
                    println!("registered: {}", resp["name"].as_str().unwrap_or(&name));
                }
                McpCmd::List => {
                    let servers = client
                        .call("mcp.list", json!({}))
                        .await
                        .context("mcp.list failed")?;
                    if let Some(arr) = servers.as_array() {
                        for s in arr {
                            println!(
                                "{} {} ({})",
                                s["name"].as_str().unwrap_or("?"),
                                s["url"].as_str().unwrap_or(""),
                                s["transport"].as_str().unwrap_or("?"),
                            );
                        }
                    }
                }
                McpCmd::Remove { name } => {
                    client
                        .call("mcp.remove", json!({ "name": name }))
                        .await
                        .context("mcp.remove failed")?;
                    println!("removed: {name}");
                }
                McpCmd::Refresh { name } => {
                    let mut params = serde_json::json!({});
                    if let Some(n) = name {
                        params["name"] = serde_json::Value::String(n);
                    }
                    let result: serde_json::Value = client
                        .call("mcp.refresh", params)
                        .await
                        .map_err(|e| anyhow::anyhow!("mcp.refresh failed: {e}"))?;
                    println!(
                        "Refreshed {} server(s)",
                        result
                            .get("refreshed")
                            .and_then(serde_json::Value::as_u64)
                            .unwrap_or(0)
                    );
                }
            }
        }
        Cmd::Prices { action } => match action {
            PricesCmd::Update { file } => {
                if let Some(src) = file {
                    // ponytail: copy file to daemon config dir; daemon reloads on next request
                    let dest = xdg_config_dir().join("smedja").join("prices.toml");
                    std::fs::copy(&src, &dest)?;
                    println!("prices.toml updated \u{2192} {}", dest.display());
                } else {
                    // Print the embedded prices.toml location
                    println!("prices.toml is read from the daemon's config directory at startup");
                }
            }
        },
        Cmd::Timeline { action } => {
            let db_path = default_ingot_path();
            let ingot = Ingot::open(&db_path)
                .with_context(|| format!("failed to open ingot at {}", db_path.display()))?;
            match action {
                TimelineCmd::Conversations { since, json } => {
                    let rollups = ingot.recent_conversations(50)?;
                    let rollups: Vec<_> = if let Some(since_secs) = since {
                        let cutoff = std::time::SystemTime::now()
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs()
                            .saturating_sub(since_secs)
                            .try_into()
                            .unwrap_or(i64::MAX);
                        rollups
                            .into_iter()
                            .filter(|r| r.started_at >= cutoff)
                            .collect()
                    } else {
                        rollups
                    };
                    if json {
                        let arr: Vec<serde_json::Value> = rollups
                            .iter()
                            .map(|r| {
                                serde_json::json!({
                                    "conversation_id": r.conversation_id,
                                    "started_at": r.started_at,
                                    "last_seen_at": r.last_seen_at,
                                    "agent_count": r.agent_count,
                                    "llm_call_count": r.llm_call_count,
                                    "tool_call_count": r.tool_call_count,
                                    "failure_count": r.failure_count,
                                    "input_token_total": r.input_token_total,
                                    "output_token_total": r.output_token_total,
                                })
                            })
                            .collect();
                        println!("{}", serde_json::to_string_pretty(&arr)?);
                    } else if rollups.is_empty() {
                        println!("No conversations found.");
                    } else {
                        println!(
                            "{:<40} {:>8} {:>8} {:>6} {:>6}",
                            "CONVERSATION", "LLM", "TOOLS", "FAIL", "TOKENS"
                        );
                        for r in &rollups {
                            println!(
                                "{:<40} {:>8} {:>8} {:>6} {:>6}",
                                &r.conversation_id[..r.conversation_id.len().min(40)],
                                r.llm_call_count,
                                r.tool_call_count,
                                r.failure_count,
                                r.input_token_total + r.output_token_total,
                            );
                        }
                    }
                }
                TimelineCmd::Show {
                    conversation_id,
                    failures_only,
                    json,
                } => {
                    let events = if failures_only {
                        ingot.failed_events(&conversation_id)?
                    } else {
                        ingot.conversation_timeline(&conversation_id)?
                    };
                    if json {
                        println!("{}", serde_json::to_string_pretty(&events)?);
                    } else if events.is_empty() {
                        println!("No events for conversation {conversation_id}");
                    } else {
                        for ev in &events {
                            println!(
                                "{:.0} {:12} {:8} {:<30} trace:{} span:{}",
                                ev.ts,
                                ev.action_type,
                                ev.status.as_deref().unwrap_or("-"),
                                ev.tool_name.as_deref().unwrap_or(ev.actor.as_str()),
                                ev.trace_id.as_deref().unwrap_or("-"),
                                ev.span_id.as_deref().unwrap_or("-"),
                            );
                        }
                    }
                }
                TimelineCmd::Open { id } => {
                    let template = std::env::var("SMEDJA_TIMELINE_URL").unwrap_or_default();
                    if template.is_empty() {
                        println!("Set SMEDJA_TIMELINE_URL to open traces in a backend.");
                        println!("Example (Honeycomb): SMEDJA_TIMELINE_URL=https://ui.honeycomb.io/your-team/environments/prod/trace?trace_id={{id}}");
                        println!("ID: {id}");
                    } else {
                        let url = template.replace("{id}", &id);
                        println!("{url}");
                    }
                }
            }
        }
        Cmd::Service { action } => service::run(&action)?,
        Cmd::Term { action } => match action {
            TermCmd::Migrate { from, out } => {
                let lua_source = std::fs::read_to_string(&from)
                    .with_context(|| format!("cannot read {}", from.display()))?;
                let result = st_config::migrate::migrate_wezterm_config(&lua_source)
                    .map_err(|e| anyhow::anyhow!("{e}"))?;

                match out {
                    Some(out_path) => {
                        std::fs::write(&out_path, &result.toml)
                            .with_context(|| format!("cannot write {}", out_path.display()))?;
                    }
                    None => {
                        print!("{}", result.toml);
                    }
                }

                eprintln!("{}", result.summary);
                if !result.unsupported.is_empty() {
                    eprintln!("Unsupported fields:");
                    for item in &result.unsupported {
                        eprintln!("  - {item}");
                    }
                }
            }
            TermCmd::Install { bin_path, prefix } => {
                let prefix = prefix.unwrap_or_else(|| {
                    std::env::var("HOME").map_or_else(
                        |_| PathBuf::from(".local/bin"),
                        |h| PathBuf::from(h).join(".local/bin"),
                    )
                });
                let url = bin_path.unwrap_or_else(|| {
                    let os = std::env::consts::OS;
                    if os == "macos" {
                        "https://github.com/mwigge/smedja/releases/latest/download/smedja-macos-x86_64.tar.gz".to_owned()
                    } else {
                        "https://github.com/mwigge/smedja/releases/latest/download/smedja-linux-x86_64.tar.gz".to_owned()
                    }
                });
                let prefix_clone = prefix.clone();
                let url_clone = url.clone();
                tokio::task::spawn_blocking(move || cmd_term_install(&url_clone, &prefix_clone))
                    .await
                    .context("install task panicked")??;
            }
        },
    }
    Ok(())
}

fn cmd_workspace_agents() -> Result<()> {
    use smedja_assayer::{Complexity, Role, Runner, Tier};

    let workspace_dir = std::env::current_dir().context("cannot determine working directory")?;
    let file_rules = smedja_assayer::load_rules(&workspace_dir).map_err(|e| anyhow::anyhow!(e))?;
    let mut assayer = smedja_assayer::Assayer::default_rules();
    assayer.prepend_rules(file_rules);

    println!("{:<15} {:<10} {:<8} MODEL", "ROLE", "RUNNER", "TIER");
    println!("{}", "-".repeat(55));

    for (role_name, role) in &[
        ("orchestrator", Role::Orchestrator),
        ("impl", Role::Impl),
        ("test", Role::Test),
        ("review", Role::Review),
        ("sre", Role::Sre),
    ] {
        let route = assayer.route(*role, Complexity::Coding);
        let runner = match route.runner {
            Runner::Claude => "claude",
            Runner::Local => "local",
            Runner::Codex => "codex",
            Runner::Copilot => "copilot",
            Runner::Minimax => "minimax",
            Runner::Berget => "berget",
        };
        let tier = match route.tier {
            Tier::Fast => "fast",
            Tier::Local => "local",
            Tier::Deep => "deep",
        };
        let model = route.model.as_deref().unwrap_or("-");
        println!("{role_name:<15} {runner:<10} {tier:<8} {model}");
    }
    Ok(())
}

async fn cmd_daemon_status(sock: &std::path::Path) -> Result<()> {
    match Client::connect(sock).await {
        Err(_) => {
            println!(
                "smdjad: not running (socket not found at {})",
                sock.display()
            );
            std::process::exit(1);
        }
        Ok(mut client) => {
            let resp = client
                .call("ping", serde_json::Value::Null)
                .await
                .with_context(|| "ping failed")?;
            println!("smdjad: running ({})", sock.display());
            println!("response: {resp}");
            Ok(())
        }
    }
}

fn cmd_daemon_start() -> Result<()> {
    // Locate smdjad relative to this binary.
    let exe = std::env::current_exe().context("cannot determine own path")?;
    let smdjad = exe
        .parent()
        .map(|p| p.join("smdjad"))
        .filter(|p| p.exists())
        .unwrap_or_else(|| PathBuf::from("smdjad"));

    std::process::Command::new(&smdjad)
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .spawn()
        .with_context(|| format!("failed to spawn {}", smdjad.display()))?;

    println!("smdjad started");
    Ok(())
}

fn cmd_skill_list(registry: &SkillRegistry) -> Result<()> {
    let skills = registry.scan()?;
    if skills.is_empty() {
        println!(
            "No skills installed at {}",
            SkillRegistry::default_path().display()
        );
        return Ok(());
    }
    println!("{:<30} {:<10} DESCRIPTION", "NAME", "VERSION");
    println!("{}", "-".repeat(80));
    for skill in &skills {
        let version = skill.manifest.version.as_deref().unwrap_or("-");
        let desc = skill
            .manifest
            .description
            .lines()
            .next()
            .unwrap_or("")
            .trim();
        println!("{:<30} {:<10} {}", skill.manifest.name, version, desc);
    }
    println!("\n{} skill(s) installed", skills.len());
    Ok(())
}

fn cmd_skill_install(registry: &SkillRegistry, path: &std::path::Path) -> Result<()> {
    let (name, content) = read_skill_file(path)?;
    registry
        .install(&name, &content)
        .with_context(|| format!("failed to install skill `{name}`"))?;
    println!("Installed skill `{name}`");
    Ok(())
}

fn cmd_skill_update(registry: &SkillRegistry, name: &str, path: &std::path::Path) -> Result<()> {
    let (_parsed_name, content) = read_skill_file(path)?;
    registry
        .update(name, &content)
        .with_context(|| format!("failed to update skill `{name}`"))?;
    println!("Updated skill `{name}`");
    Ok(())
}

fn cmd_skill_remove(registry: &SkillRegistry, name: &str) -> Result<()> {
    registry
        .remove(name)
        .with_context(|| format!("failed to remove skill `{name}`"))?;
    println!("Removed skill `{name}`");
    Ok(())
}

fn cmd_skill_sync(registry: &SkillRegistry, path: &std::path::Path) -> Result<()> {
    println!("Syncing from {} ...", path.display());
    let r = registry
        .sync_from(path)
        .with_context(|| format!("sync failed from {}", path.display()))?;
    for (name, reason) in &r.errors {
        println!("  error:   {name} — {reason}");
    }
    println!(
        "\n{} linked, {} updated, {} skipped, {} error(s)",
        r.linked,
        r.updated,
        r.skipped,
        r.errors.len()
    );
    Ok(())
}

